Flight::route('GET /erp/all-tasks(/@filter\_status)', function ($filter\_status) {
 global $m, $rm, $db;

 $cookie = (array)Flight::jwt()::decode($\_COOKIE['webapp\_enc'], Flight::get('key'), array('HS256'));

 $user\_id = $rm->get('tbl\_users', 'user\_id', array(
 'token' => $cookie['token']
 ));
 if (!$user\_id) {

 $admin\_id = $db->get('mt\_admin\_user', 'admin\_id', array(
 'token' => $cookie['token']
 ));

 $user\_id = $rm->get('tbl\_users', 'user\_id', array(
 'sync\_id' => $admin\_id
 ));
 if(!$user\_id) {

 $user\_id = $rm->get('tbl\_users', 'user\_id', array(
 'sync\_id' => getKmrsId()
 ));
 }
 }
 $where = array();
 if(!empty($filter\_status)) {
 $where['category\_id'] = $filter\_status;
 }
 $tasks = $rm->select('tbl\_task', '\*', $where);
 $completed\_count = $rm->count("tbl\_task", array\_merge($where, [
 "task\_status" => "completed",
 ]));
 $in\_progress\_count = $rm->count("tbl\_task", array\_merge($where, [
 "task\_status" => "in\_progress",
 ]));
 $deferred\_count = $rm->count("tbl\_task", array\_merge($where, [
 "task\_status" => "deferred",
 ]));
 $not\_started\_count = $rm->count("tbl\_task", array\_merge($where, [
 "task\_status" => "not\_started",
 ]));
 $waiting\_for\_someone\_count = $rm->count("tbl\_task", array\_merge($where, [
 "task\_status" => "waiting\_for\_someone",
 ]));
 $tasks = array\_map(function($elem) use ($db, $rm, $user\_id) {
 $elem['category\_name'] = $rm->get('tbl\_customer\_group', 'customer\_group', array(
 'customer\_group\_id' => $elem['category\_id']
 ));
 $elem['invoice'] = false; 
 if($elem['invoice\_id'] > 0) {
 // innerjoin with tbl\_client
 $invoices = $rm->select('tbl\_invoices', array(
 '[><]tbl\_client' => ['client\_id' => 'client\_id']
 ) , array(
 'tbl\_invoices.invoices\_id',
 'tbl\_invoices.due\_date',
 'tbl\_invoices.reference\_no',
 'tbl\_invoices.status',
 'tbl\_invoices.invoice\_date',
 'tbl\_client.sync\_id',
 'tbl\_client.merchant\_name',
 'tbl\_client.merchant\_phone',
 'tbl\_client.expires\_date',
 'tbl\_client.last\_login',
 'tbl\_client.client\_id',
 'tbl\_client.name',
 ), array(
 'tbl\_invoices.invoices\_id' => $elem['invoice\_id']
 ));

 $invoices = array\_map(function ($invoice) use ($rm) {
 $due\_amount = $rm->sum('tbl\_items', 'total\_cost', array(
 'invoices\_id' => $invoice['invoices\_id']
 ));
 $invoice['due\_amount'] = $due\_amount;
 switch ($invoice['status']) {
 case 'paid':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 case 'rejected':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 case 'unpaid':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 case 'overdue':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 case 'draft':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 case 'partially\_paid':
 $invoice['status'] = '' . t($invoice['status']) . '';
 break;
 }
 /\*$invoice['published'] = $invoice['status'];
 if ($invoice['published'] == 2) {
 $invoice['rejected'] = true;
 }\*/
 /\*$invoice['items'] = $rm->select('ready\_invoice\_items', '\*', array(
 'ri\_invoice\_id' => $invoice['id']
 ));\*/
 return $invoice;
 }, $invoices);

 $elem['invoice'] = $invoices[0]; 
 } 
 switch($elem['task\_status']) {
 case 'completed':
 $elem['completed'] = true;
 break;
 case 'not\_started':
 $elem['task\_status'] = t('Not Started');
 break;
 case 'in\_progress':
 $elem['task\_status'] = t('In progress');
 break;

 }
 if($elem['merchant\_id'] > 0) {
 $elem['store'] = $db->get('mt\_merchant', '\*', array(
 'merchant\_id' => $elem['merchant\_id']
 ));
 $elem['store']['published'] = $elem['store']['is\_ready'] == 2 ? true : false;
 }
 $elem['assigned'] = array();
 $elem['assigned\_to\_me'] = false;
 $assigneds = (array)json\_decode($elem['permission'], true);
 foreach($assigneds as $key=>$val) {
 if($key == $user\_id) {
 $elem['assigned\_to\_me'] = true;
 }
 $as\_find = $rm->get('tbl\_users', 'username', array(
 'user\_id' => $key
 ));
 if($as\_find) {
 $elem['assigned'][] = $as\_find;
 }
 }
 return $elem;
 }, $tasks);

 echo $m->render('erp/task/task\_all', array(
 'completed\_count' => $completed\_count,
 'in\_progress\_count' => $in\_progress\_count,
 'deferred\_count' => $deferred\_count,
 'not\_started\_count' => $not\_started\_count,
 'waiting\_for\_someone\_count' => $waiting\_for\_someone\_count,
 'title' => t('All Tasks'),
 'tasks' => $tasks,
 'tasks\_count' => count($tasks),
 'task\_type' => 'all-tasks',
 'filter\_status' => $filter\_status
 ));
});

