 ]));
 $waiting\_for\_someone\_count = $rm->count("tbl\_task", array\_merge($where\_two, [
 "task\_status" => "waiting\_for\_someone",
 'OR' => [
 'permission[REGEXP]' => '"[^"]\*[[:<:]]' . $user\_id . '[[:>:]]',

 ]
 ]));
 $tasks = array\_map(function($elem) use ($db, $rm, $user\_id) {
 $elem['category\_name'] = $rm->get('tbl\_customer\_group', 'customer\_group', array(
 'customer\_group\_id' => $elem['category\_id']
 ));
 switch($elem['task\_status']) {
 case 'completed':
 $elem['completed'] = true;
 break;
 case 'not\_started':
 $elem['task\_status'] = t('Not Started');
 break;
 case 'in\_progress':
 $elem['task\_status'] = t('In progress');
 break;
 case 'waiting\_for\_someone':
 $elem['task\_status'] = t('Waiting for Someone');
 break;
 }
 if($elem['merchant\_id'] > 0) {
 $elem['store'] = $db->get('mt\_merchant', '\*', array(
 'merchant\_id' => $elem['merchant\_id']
 ));
 $elem['store']['published'] = $elem['store']['is\_ready'] == 2 ? true : false; 
 }
 $elem['assigned'] = array();
 $elem['assigned\_to\_me'] = false;
 $assigneds = (array)json\_decode($elem['permission'], true);
 foreach($assigneds as $key=>$val) {
 if($key == $user\_id) {
 $elem['assigned\_to\_me'] = true;
 }
 $as\_find = $rm->get('tbl\_users', 'username', array(
 'user\_id' => $key
 ));
 if($as\_find) {
 $elem['assigned'][] = $as\_find;
 }
 }
 return $elem;
 }, $tasks);

 echo $m->render('erp/task/task\_all', array(
 'completed\_count' => $completed\_count,
